#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int x1, y1, x2, y2, x3, y3, x4, y4, x5, y5, x6, y6, x7, y7, x8, y8;
        scanf("%d %d", &x1, &y1);
        scanf("%d %d", &x2, &y2);
        scanf("%d %d", &x3, &y3);
        scanf("%d %d", &x4, &y4);
        scanf("%d %d", &x5, &y5);
        scanf("%d %d", &x6, &y6);
        scanf("%d %d", &x7, &y7);
        scanf("%d %d", &x8, &y8);
        double area_triangle1 = 0.5 * abs(x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2));
        double area_triangle2 = 0.5 * abs(x4 * (y5 - y6) + x5 * (y6 - y4) + x6 * (y4 - y5));
        double area_quadrilateral = 0.5 * abs(x7 * (y8 - y7) + x8 * (y7 - y8));
        if (area_triangle1 + area_triangle2 == area_quadrilateral) {
            printf("Yes\n");
        } else {
            printf("No\n");
        }
    }
    return 0;
}

